import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { Opportunity, STAGE_META } from '../../models/models';

@Component({
  selector: 'app-opportunity-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './opportunity-list.component.html',
  styleUrl: './opportunities.css',
})
export class OpportunityListComponent {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  readonly stageMeta = STAGE_META;

  private params = toSignal(this.route.queryParamMap, { initialValue: this.route.snapshot.queryParamMap });
  readonly stage = computed(() => this.params().get('stage') ?? '');
  readonly search = computed(() => this.params().get('q') ?? '');

  opportunities = signal<Opportunity[]>([
    { id: 'o1', name: 'Acme — Platform Renewal', accountId: 'a1', accountName: 'Acme Corporation', stage: 'NEGOTIATION', amount: 120000, closeDate: '2026-08-15', probability: 75, owner: 'Demo Admin' },
    { id: 'o2', name: 'Globex Data Migration', accountId: 'a2', accountName: 'Globex Industries', stage: 'PROPOSAL', amount: 84000, closeDate: '2026-07-30', probability: 60, owner: 'Priya Nair' },
    { id: 'o3', name: 'Initech Security Suite', accountId: 'a3', accountName: 'Initech', stage: 'QUALIFICATION', amount: 45000, closeDate: '2026-09-05', probability: 40, owner: 'Marco Diaz' },
    { id: 'o4', name: 'Umbrella Analytics Rollout', accountId: 'a4', accountName: 'Umbrella Health', stage: 'PROSPECTING', amount: 210000, closeDate: '2026-10-12', probability: 20, owner: 'Demo Admin' },
    { id: 'o5', name: 'Soylent Cloud Expansion', accountId: 'a5', accountName: 'Soylent Foods', stage: 'CLOSED_WON', amount: 156000, closeDate: '2026-06-28', probability: 100, owner: 'Priya Nair' },
    { id: 'o6', name: 'Acme Field Service Add-on', accountId: 'a1', accountName: 'Acme Corporation', stage: 'PROPOSAL', amount: 38000, closeDate: '2026-09-20', probability: 55, owner: 'Priya Nair' },
    { id: 'o7', name: 'Stark Energy Grid Platform', accountId: 'a6', accountName: 'Stark Energy', stage: 'NEEDS_ANALYSIS', amount: 340000, closeDate: '2026-11-01', probability: 45, owner: 'Marco Diaz' },
    { id: 'o8', name: 'Wayne Media CDP', accountId: 'a7', accountName: 'Wayne Media', stage: 'QUALIFICATION', amount: 72000, closeDate: '2026-08-22', probability: 35, owner: 'Demo Admin' },
    { id: 'o9', name: 'Hooli Cloud Migration', accountId: 'a8', accountName: 'Hooli Cloud', stage: 'NEGOTIATION', amount: 265000, closeDate: '2026-07-18', probability: 80, owner: 'Priya Nair' },
    { id: 'o10', name: 'Pied Piper Compression Pilot', accountId: 'a10', accountName: 'Pied Piper', stage: 'PROSPECTING', amount: 28000, closeDate: '2026-10-30', probability: 15, owner: 'Marco Diaz' },
    { id: 'o11', name: 'Vandelay Import Portal', accountId: 'a9', accountName: 'Vandelay Imports', stage: 'CLOSED_LOST', amount: 51000, closeDate: '2026-06-10', probability: 0, owner: 'Demo Admin' },
    { id: 'o12', name: 'Umbrella Telehealth Suite', accountId: 'a4', accountName: 'Umbrella Health', stage: 'PROPOSAL', amount: 190000, closeDate: '2026-09-14', probability: 65, owner: 'Priya Nair' },
  ]);

  readonly filtered = computed(() => {
    const q = this.search().toLowerCase().trim();
    const st = this.stage();
    return this.opportunities().filter((o) => {
      const mq = !q || o.name.toLowerCase().includes(q) || o.accountName.toLowerCase().includes(q);
      const ms = !st || o.stage === st;
      return mq && ms;
    });
  });

  stageLabel(key: string): string {
    return this.stageMeta.find((s) => s.key === key)?.label ?? key;
  }
  stageColor(key: string): string {
    return this.stageMeta.find((s) => s.key === key)?.color ?? 'var(--color-text-muted)';
  }

  onSearch(v: string): void {
    this.router.navigate([], { queryParams: { q: v || null }, queryParamsHandling: 'merge' });
  }
  onStage(v: string): void {
    this.router.navigate([], { queryParams: { stage: v || null }, queryParamsHandling: 'merge' });
  }
}
